class Solution:
    def numMusicPlaylists(self, n: int, goal: int, k: int) -> int:
        MOD = 10**9 + 7
        @lru_cache(None)
        def dp(i, j):
            if i == goal:
                return int(j == n)
            res = 0
            if j < n:
                res += (n - j) * dp(i + 1, j + 1)
            if j >= k:
                res += j * dp(i + 1, j)
            return res % MOD
        return dp(0, 0)
```
